use axon_schema::schema::CollectionSchema;
use axon_storage::SqliteStorageAdapter;
use clap::{Parser, Subcommand, ValueEnum};
use serde_json::Value;

// ── Output format ──────────────────────────────────────────────────────────────

#[derive(Clone, Debug, ValueEnum, Default)]
enum OutputFormat {
    #[default]
    Table,
    Json,
    Yaml,
}

#[derive(Clone, Debug, ValueEnum, Default)]
enum EntityRenderFormat {
    #[default]
    Json,
    Markdown,
}

// ── CLI structure ──────────────────────────────────────────────────────────────

#[derive(Parser)]
#[command(name = "axon", about = "Axon data store CLI", version)]
pub struct Cli {
    /// Path to the SQLite database file (default: XDG data dir).
    #[arg(long, global = true)]
    db: Option<String>,

    /// Output format.
    #[arg(long, default_value = "table", global = true)]
    output: OutputFormat,

    #[command(subcommand)]
    command: Command,
}

#[derive(Subcommand)]
enum Command {
    /// Database management.
    #[command(subcommand)]
    Database(DatabaseCmd),

    /// Namespace management.
    #[command(subcommand)]
    Namespace(NamespaceCmd),

    /// Collection management.
    #[command(subcommand)]
    Collections(CollectionCmd),

    /// Entity operations.
    #[command(subcommand)]
    Entities(EntityCmd),

    /// Link operations.
    #[command(subcommand)]
    Links(LinkCmd),

    /// Audit log queries.
    #[command(subcommand)]
    Audit(AuditCmd),

    /// Schema operations.
    #[command(subcommand)]
    Schema(SchemaCmd),

    /// Show current configuration.
    #[command(subcommand)]
    Config(ConfigCmd),

    /// Bead (work item) management.
    #[command(subcommand)]
    Bead(BeadCmd),

    /// Start the Axon server (HTTP gateway, optional gRPC).
    #[cfg(feature = "serve")]
    Serve(axon_server::serve::ServeArgs),

    /// Start MCP server over stdin/stdout.
    #[cfg(feature = "serve")]
    Mcp {
        /// Backing storage adapter.
        #[arg(long, env = "AXON_STORAGE", value_enum, default_value = "sqlite")]
        storage: axon_server::serve::StorageBackend,
        /// SQLite database path.
        #[arg(long, env = "AXON_SQLITE_PATH", default_value = "axon.db")]
        sqlite_path: String,
        /// PostgreSQL DSN.
        #[arg(long, env = "AXON_POSTGRES_DSN")]
        postgres_dsn: Option<String>,
    },

    /// Show diagnostic information about the Axon installation.
    Doctor,

    /// Initialize a new Axon project.
    Init {
        /// Project name (also used as directory name).
        name: String,
    },

    /// Manage Axon as a system service (install, start, stop, …).
    #[command(subcommand)]
    Server(ServerCmd),

    /// Traverse entity relationships as a graph (shorthand for `links traverse`).
    Graph {
        /// Source collection.
        collection: String,
        /// Source entity ID.
        id: String,
        /// Restrict traversal to this link type.
        #[arg(long, short = 't')]
        link_type: Option<String>,
        /// Maximum hop depth (default: 1).
        #[arg(long, short = 'd', default_value = "1")]
        depth: usize,
    },

    /// Policy explanation and testing (CONTRACT-008).
    #[command(subcommand)]
    Policy(PolicyCmd),

    /// Governed-write mutation intent workflow (CONTRACT-008).
    #[command(subcommand)]
    Mutation(MutationCmd),

    /// Rollback operations (CONTRACT-008).
    #[command(subcommand)]
    Rollback(RollbackCmd),

    /// Manage per-principal role assignments.
    #[cfg(feature = "serve")]
    #[command(subcommand)]
    User(UserCmd),

    /// Manage CORS allowed origins for browser-based clients.
    #[cfg(feature = "serve")]
    #[command(subcommand)]
    Cors(CorsCmd),
}

#[cfg(feature = "serve")]
#[derive(Subcommand, Clone)]
enum UserCmd {
    /// Grant a role to a principal (creates or updates the assignment).
    Grant {
        /// The user's login name (e.g. `erik@example.com`).
        login: String,
        /// The role to assign: `admin`, `write`, or `read`.
        role: String,
    },
    /// Revoke the explicit role assignment for a principal.
    ///
    /// After revocation, the principal falls back to tag-based or default role
    /// resolution on their next request.
    Revoke {
        /// The user's login name.
        login: String,
    },
    /// List all explicit user-role assignments.
    List,
}

#[cfg(feature = "serve")]
#[derive(Subcommand, Clone)]
enum CorsCmd {
    /// Add an allowed CORS origin (e.g. `https://sindri:5173`).
    ///
    /// Use `*` to enable wildcard mode, which allows all origins.
    Add {
        /// The origin to allow (scheme + host + optional port).
        origin: String,
    },
    /// Remove an allowed CORS origin.
    Remove {
        /// The origin to remove.
        origin: String,
    },
    /// List all allowed CORS origins.
    List,
}

#[derive(Subcommand)]
enum ConfigCmd {
    /// Print resolved configuration.
    Show,
    /// Print config file path.
    Path,
}

#[derive(Subcommand)]
enum ServerCmd {
    /// Install Axon as a user service (systemd on Linux, launchd on macOS).
    ///
    /// Service installs default to authenticated mode (CONTRACT-008 / FEAT-028 BIN-10).
    /// Pass --no-auth to opt out; a prominent warning is printed naming the exposure.
    Install {
        /// Install as a system-wide service (requires root).
        #[arg(long)]
        global: bool,
        /// Disable authentication in the installed service unit (explicit opt-out).
        ///
        /// All requests will succeed as admin without credentials. Only use this when
        /// the server is protected by other means. A prominent warning is printed.
        #[arg(long)]
        no_auth: bool,
    },
    /// Remove the Axon service.
    Uninstall,
    /// Start the Axon service.
    Start,
    /// Stop the Axon service.
    Stop,
    /// Restart the Axon service.
    Restart,
    /// Show Axon service status.
    Status,
}

#[derive(Subcommand)]
enum DatabaseCmd {
    /// Create a database and its default schema.
    Create { name: String },
    /// List databases.
    List,
    /// Drop a database.
    Drop {
        name: String,

        name: String,
        #[arg(long)]
        force: bool,
        #[arg(long)]
        confirm: bool,
    },
}

#[derive(Subcommand)]
enum NamespaceCmd {
    /// Create a schema namespace within a database.
    Create {
        #[arg(long)]
        database: String,
        schema: String,
    },
    /// List schemas within a database.
    List {
        #[arg(long)]
        database: String,
    },
    /// List collections within a namespace.
    Collections {
        #[arg(long)]
        database: String,
        schema: String,
    },
    /// Drop a schema namespace.
    Drop {
        #[arg(long)]
        database: String,
        schema: String,
