        force: bool,
        #[arg(long)]
        confirm: bool,
    },
}

// ── Collection commands ────────────────────────────────────────────────────────

#[derive(Subcommand)]
enum CollectionCmd {
    /// Create a named collection with a schema.
    Create {
        /// Collection name.
        name: String,
        /// Schema JSON (entity_schema). If omitted, creates a schemaless collection.
        #[arg(long)]
        schema: Option<String>,
        #[arg(long)]
        actor: Option<String>,
    },
    /// List all registered collections.
    List,
    /// Drop a collection and all its entities.
    Drop {
        /// Collection name.
        name: String,
        #[arg(long)]
        actor: Option<String>,
        /// Confirm the destructive operation.
        #[arg(long)]
        confirm: bool,
    },
    /// Describe a collection (entity count, schema, timestamps).
    Describe {
        /// Collection name.
        name: String,
    },
    /// Manage a collection's markdown template.
    #[command(subcommand)]
    Template(CollectionTemplateCmd),
}

#[derive(Subcommand)]
enum CollectionTemplateCmd {
    /// Save or replace the markdown template for a collection.
    Put {
        collection: String,
        #[arg(long)]
        template: Option<String>,
        #[arg(long)]
        file: Option<String>,
        #[arg(long)]
        actor: Option<String>,
    },
    /// Show the markdown template for a collection.
    Get { collection: String },
    /// Delete the markdown template for a collection.
    Delete {
        collection: String,
        #[arg(long)]
        actor: Option<String>,
    },
}

// ── Entity commands ────────────────────────────────────────────────────────────

#[derive(Subcommand)]
enum EntityCmd {
    /// Create a new entity.
    Create {
        /// Collection name.
        collection: String,
        /// Entity ID.
        #[arg(long, short = 'i')]
        id: String,
        /// Entity data as a JSON string.
        #[arg(long, short = 'd')]
        data: String,
        #[arg(long)]
        actor: Option<String>,
    },
    /// Retrieve an entity.
    Get {
        collection: String,
        id: String,
        #[arg(long, default_value = "json")]
        render: EntityRenderFormat,
    },
    /// List entities in a collection.
    List {
        collection: String,
        /// Maximum number of entities to return.
        #[arg(long)]
        limit: Option<usize>,
    },
    /// Update an entity (optimistic concurrency control).
    ///
    /// If --expected-version is omitted the current version is fetched automatically.
    Update {
        collection: String,
        id: String,
        /// Updated data as a JSON string.
        #[arg(long, short = 'd')]
        data: String,
        /// Expected version for OCC. Auto-fetched if omitted.
        #[arg(long)]
        expected_version: Option<u64>,
        #[arg(long)]
        actor: Option<String>,
    },
    /// Delete an entity.
    Delete {
        collection: String,
        id: String,
        #[arg(long)]
        actor: Option<String>,
    },
    /// Query entities with filter expressions.
    ///
    /// Filters use `field=value` syntax (equality). Multiple filters are ANDed.
    Query {
        collection: String,
        /// Filter expressions (e.g. `status=open`). Multiple allowed, ANDed together.
        #[arg(long, num_args = 1..)]
        filter: Vec<String>,
        #[arg(long)]
        limit: Option<usize>,
        /// Return only the count of matching entities.
        #[arg(long)]
        count_only: bool,
    },
}

