        target_id: String,
        /// Link type label.
        #[arg(long = "type", short = 't')]
        link_type: String,
        #[arg(long)]
        actor: Option<String>,
    },
    /// List direct outbound links from an entity.
    List {
        collection: String,
        id: String,
        /// Restrict to this link type.
        #[arg(long, short = 't')]
        link_type: Option<String>,
    },
    /// Traverse links from a source entity (multi-hop graph walk).
    Traverse {
        collection: String,
        id: String,
        /// Restrict traversal to this link type.
        #[arg(long, short = 't')]
        link_type: Option<String>,
        /// Maximum hop depth (default: unlimited).
        #[arg(long, short = 'd')]
        max_depth: Option<usize>,
    },
    /// Create a directed link (explicit long-form flags).
    Create {
        #[arg(long)]
        source_collection: String,
        #[arg(long)]
        source_id: String,
        #[arg(long)]
        target_collection: String,
        #[arg(long)]
        target_id: String,
        #[arg(long)]
        link_type: String,
        #[arg(long)]
        actor: Option<String>,
    },
}

